UPDATE er.tn_oom_check_vrfr_eval
   SET eval_grd_cd      = #{evalGrdCd},
       eval_rmrk        = #{evalRmrk},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE oom_id        = #{oomId}
   AND vrfcn_inst_id = #{vrfcnInstId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_oom_check_vrfr_eval
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE oom_id        = #{oomId}
   AND vrfcn_inst_id = #{vrfcnInstId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
